import { readFileSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";

const rootDir = resolve(import.meta.dirname, "..");
const docsDir = resolve(rootDir, "packages/react-webcam/pkg-docs");
const generatedNotice =
  "<!-- This file is generated by `pnpm readme:package`. Edit packages/react-webcam/pkg-docs/README.en.md and packages/react-webcam/pkg-docs/README.ko.md instead. -->";
const readmeTargets = [
  {
    sourcePath: resolve(docsDir, "README.en.md"),
    outputPath: resolve(rootDir, "packages/react-webcam/README.md"),
    languageLink: "[한국어 README](./README.ko.md)",
  },
  {
    sourcePath: resolve(docsDir, "README.ko.md"),
    outputPath: resolve(rootDir, "packages/react-webcam/README.ko.md"),
    languageLink: "[English README](./README.md)",
  },
];

function buildOutput(source, languageLink) {
  return `${languageLink}\n\n${generatedNotice}\n\n${source.trim()}\n`;
}

if (process.argv.includes("--check")) {
  for (const target of readmeTargets) {
    const source = readFileSync(target.sourcePath, "utf8");
    const output = buildOutput(source, target.languageLink);
    const current = readFileSync(target.outputPath, "utf8");

    if (current !== output) {
      throw new Error(
        `Generated content does not match ${target.outputPath}. Run pnpm readme:package.`,
      );
    }
  }

  console.log("[readme:package:check] README files are in sync.");
  process.exit(0);
}

for (const target of readmeTargets) {
  const source = readFileSync(target.sourcePath, "utf8");
  const output = buildOutput(source, target.languageLink);
  writeFileSync(target.outputPath, output);
  console.log(`[readme:package] Wrote ${target.outputPath}.`);
}
